// ============================================================================
// Config loading
// ============================================================================

function loadConfig(): PrunerConfig {
  try {
    const fs = require("fs")
    const path = require("path")
    const configPath = path.join(process.cwd(), PRUNER_CONFIG_PATH)
    if (!fs.existsSync(configPath)) {
      return { ...DEFAULT_CONFIG }
    }
    const raw = fs.readFileSync(configPath, "utf-8")
    const parsed = JSON.parse(raw)
    if (parsed.pluginApiVersion !== PRUNER_API_VERSION) {
      console.warn(
        `[sigil-pruner] Config API version mismatch: expected ${PRUNER_API_VERSION}, got ${parsed.pluginApiVersion}. Disabling pruner.`
      )
      return { ...DEFAULT_CONFIG, enabled: false }
    }
    return { ...DEFAULT_CONFIG, ...parsed }
  } catch (e) {
    console.warn("[sigil-pruner] Failed to load config, using defaults:", e)
    return { ...DEFAULT_CONFIG }
  }
}

