// ============================================================================
// messages.transform hook
// ============================================================================

function createMessageTransformHandler(
  config: PrunerConfig,
  state: SessionState,
  directory: string
): (input: {}, output: { messages: MessageWithParts[] }) => Promise<void> {
  return async (_input, output) => {
    const messages = output.messages
    if (!messages || messages.length === 0) return

    // Derive session id from first message if not set
    if (!state.sessionId && messages[0]?.info?.metadata?.sessionID) {
      state.sessionId = messages[0].info.metadata.sessionID
    }

    assignMessageRefs(state, messages)
    cacheMessages(state, messages)
    syncCompressionBlocks(state, messages)
    syncToolCache(state, messages)

    if (config.deterministic.dedupEnabled) {
      deduplicateToolCalls(state, messages)
    }

    if (config.deterministic.pruneOldToolOutputs) {
      pruneOldToolOutputs(state, messages, config.deterministic.maxToolOutputMessages, config)
    }

    if (config.deterministic.pruneErroredToolInputs) {
      pruneErroredToolInputs(state, messages, config.deterministic.erroredToolTurns)
    }

    applyCompressionBlocks(state, messages)

    // Write heartbeat (JSON format — Kotlin PrunerHeartbeatReader parses tokensSaved)
    state.lastHeartbeatMs = Date.now()
    writeHeartbeat(state.lastHeartbeatMs, directory, state.stats)
  }
}

